import './CardTile.css'

export default function CardTile({ card, onCardClick }) {
  function handleKeyDown(e) {
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault()
      onCardClick(card)
    }
  }

  return (
    <div
      className="card-tile"
      role="button"
      tabIndex={0}
      onClick={() => onCardClick(card)}
      onKeyDown={handleKeyDown}
      aria-label={card.title}
    >
      <h3 className="card-tile-title">{card.title}</h3>
      <p className="card-tile-assignee">{card.assignee ?? 'Unassigned'}</p>
      {card.description && (
        <p className="card-tile-description">{card.description}</p>
      )}
    </div>
  )
}

import { render, screen, fireEvent, within } from '@testing-library/react'
import { describe, it, expect, vi, beforeEach } from 'vitest'
import { useBoard } from '../../hooks/useBoard.js'
import Board from './Board.jsx'

vi.mock('../../hooks/useBoard.js', () => ({ useBoard: vi.fn() }))

const MOCK_CARD = {
  id: 'c1',
  title: 'Test Card',
  assignee: 'Alice',
  description: 'A description',
  column: 'ready',
  position: 1,
  created_at: Date.now(),
  comments: [],
}

const DEFAULT_STATE = {
  cards: { ready: [], in_progress: [], done: [] },
  loading: false,
  error: null,
  createCard: vi.fn(),
  updateCard: vi.fn(),
  deleteCard: vi.fn(),
  moveCard: vi.fn(),
  addComment: vi.fn(),
}

beforeEach(() => {
  useBoard.mockReturnValue(DEFAULT_STATE)
})

describe('Board', () => {
  it('renders three column regions', () => {
    render(<Board />)
    expect(screen.getAllByRole('region')).toHaveLength(3)
  })

  it('renders Ready column heading', () => {
    render(<Board />)
    expect(screen.getByRole('heading', { name: 'Ready' })).toBeInTheDocument()
  })

  it('renders In Progress column heading', () => {
    render(<Board />)
    expect(screen.getByRole('heading', { name: 'In Progress' })).toBeInTheDocument()
  })

  it('renders Done column heading', () => {
    render(<Board />)
    expect(screen.getByRole('heading', { name: 'Done' })).toBeInTheDocument()
  })

  it('shows loading indicator when loading is true', () => {
    useBoard.mockReturnValue({ ...DEFAULT_STATE, loading: true })
    render(<Board />)
    expect(screen.getByLabelText('Loading')).toBeInTheDocument()
    expect(screen.queryAllByRole('region')).toHaveLength(0)
  })

  it('shows error banner when error is set', () => {
    useBoard.mockReturnValue({ ...DEFAULT_STATE, error: 'fetch failed' })
    render(<Board />)
    expect(screen.getByRole('alert')).toHaveTextContent('fetch failed')
  })

  it('passes ready cards to Ready column', () => {
    useBoard.mockReturnValue({
      ...DEFAULT_STATE,
      cards: { ready: [MOCK_CARD], in_progress: [], done: [] },
    })
    render(<Board />)
    expect(
      within(screen.getByRole('region', { name: 'Ready' })).getByText('Test Card')
    ).toBeInTheDocument()
  })

  it('passes in_progress cards to In Progress column', () => {
    useBoard.mockReturnValue({
      ...DEFAULT_STATE,
      cards: { ready: [], in_progress: [{ ...MOCK_CARD, id: 'c2', column: 'in-progress' }], done: [] },
    })
    render(<Board />)
    expect(
      within(screen.getByRole('region', { name: 'In Progress' })).getByText('Test Card')
    ).toBeInTheDocument()
  })

  it('passes done cards to Done column', () => {
    useBoard.mockReturnValue({
      ...DEFAULT_STATE,
      cards: { ready: [], in_progress: [], done: [{ ...MOCK_CARD, id: 'c3', column: 'done' }] },
    })
    render(<Board />)
    expect(
      within(screen.getByRole('region', { name: 'Done' })).getByText('Test Card')
    ).toBeInTheDocument()
  })

  it('opens modal when a card is clicked', () => {
    useBoard.mockReturnValue({
      ...DEFAULT_STATE,
      cards: { ready: [MOCK_CARD], in_progress: [], done: [] },
    })
    render(<Board />)
    fireEvent.click(screen.getByRole('button', { name: 'Test Card' }))
    expect(screen.getByRole('dialog')).toBeInTheDocument()
  })

  it('closes modal when close button is clicked', () => {
    useBoard.mockReturnValue({
      ...DEFAULT_STATE,
      cards: { ready: [MOCK_CARD], in_progress: [], done: [] },
    })
    render(<Board />)
    fireEvent.click(screen.getByRole('button', { name: 'Test Card' }))
    fireEvent.click(screen.getByRole('button', { name: /close/i }))
    expect(screen.queryByRole('dialog')).toBeNull()
  })

  it('modal reflects updated card data when useBoard cards state changes', () => {
    const card = { ...MOCK_CARD, title: 'Old Title' }
    useBoard.mockReturnValue({
      ...DEFAULT_STATE,
      cards: { ready: [card], in_progress: [], done: [] },
    })
    const { rerender } = render(<Board />)
    fireEvent.click(screen.getByRole('button', { name: 'Old Title' }))
    expect(screen.getByRole('dialog')).toHaveTextContent('Old Title')

    // Simulate useBoard updating the card in place (e.g. after updateCard resolves)
    useBoard.mockReturnValue({
      ...DEFAULT_STATE,
      cards: { ready: [{ ...card, title: 'New Title' }], in_progress: [], done: [] },
    })
    rerender(<Board />)
    expect(screen.getByRole('dialog')).toHaveTextContent('New Title')
  })

  it('modal closes automatically when selected card is removed from cards state', () => {
    useBoard.mockReturnValue({
      ...DEFAULT_STATE,
      cards: { ready: [MOCK_CARD], in_progress: [], done: [] },
    })
    const { rerender } = render(<Board />)
    fireEvent.click(screen.getByRole('button', { name: 'Test Card' }))
    expect(screen.getByRole('dialog')).toBeInTheDocument()

    // Simulate card being deleted from state
    useBoard.mockReturnValue({
      ...DEFAULT_STATE,
      cards: { ready: [], in_progress: [], done: [] },
    })
    rerender(<Board />)
    expect(screen.queryByRole('dialog')).toBeNull()
  })
})

import { useState, useEffect, useCallback, useRef } from 'react'
import {
  fetchCards,
  createCard as apiCreateCard,
  updateCard as apiUpdateCard,
  deleteCard as apiDeleteCard,
  createComment,
} from '../api/client.js'
import { useWebSocket } from './useWebSocket.js'

// ---------------------------------------------------------------------------
// Module-level helpers
// ---------------------------------------------------------------------------

/**
 * Map API column value → state key.
 * 'in-progress' (hyphen) → 'in_progress' (underscore); others pass through.
 * @param {string} col
 * @returns {string}
 */
export function columnToKey(col) {
  return col === 'in-progress' ? 'in_progress' : col
}

/**
 * Group a flat array of cards into the board state shape, sorted by position.
 * @param {import('../api/client.js').Card[]} cards
 * @returns {{ ready: Card[], in_progress: Card[], done: Card[] }}
 */
function groupCards(cards) {
  const board = { ready: [], in_progress: [], done: [] }
  for (const card of cards) {
    const key = columnToKey(card.column)
    if (key in board) board[key].push(card)
  }
  for (const key of Object.keys(board)) {
    board[key].sort((a, b) => a.position - b.position)
  }
  return board
}

const EMPTY_BOARD = { ready: [], in_progress: [], done: [] }

// Temp-ID counter for optimistic records (module-level so it's stable across renders)
let _tempId = 0
function nextTempId() {
  return '__temp_' + (++_tempId)
}

// WebSocket constants (module-level — computed once on import)
const WS_URL = `${location.protocol === 'https:' ? 'wss:' : 'ws:'}//${location.host}/ws`
const WS_EVENTS = ['card:created', 'card:updated', 'card:deleted', 'card:moved', 'comment:created']

// ---------------------------------------------------------------------------
// useBoard hook
// ---------------------------------------------------------------------------

/**
 * Manages board state: cards grouped by column, loading, and error.
 *
 * Column convention
 *   - State keys:  ready | in_progress | done  (underscore)
 *   - API values:  ready | in-progress  | done  (hyphen for in-progress)
 *   - All hook functions that accept a column name expect the API format.
 *   - Each card's .column field retains the API format.
 *
 * @returns {{
 *   cards: { ready: Card[], in_progress: Card[], done: Card[] },
 *   loading: boolean,
 *   error: string|null,
 *   createCard: (data: object) => Promise<Card>,
 *   updateCard: (id: string, data: object) => Promise<Card>,
 *   deleteCard: (id: string) => Promise<void>,
 *   moveCard: (id: string, targetColumn: string, position?: number) => Promise<Card>,
 *   addComment: (cardId: string, data: object) => Promise<Comment>,
 * }}
 */
export function useBoard() {
  const [cards, setCards] = useState(EMPTY_BOARD)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState(null)

  // Counter for concurrent in-flight operations so loading stays true
  // until the LAST operation finishes.
  const pendingRef = useRef(0)

  // Ref that always holds the latest cards state so we can read it
  // synchronously (functional updaters are called lazily by React, which
  // would leave a rollback variable null if the API rejects as a microtask
  // before the updater runs).
  const cardsRef = useRef(EMPTY_BOARD)

  // Suppression map — consume-once with 5s TTL to ignore WS echo of local actions
  const suppressedRef = useRef(new Map())

  // Tracks whether we've had at least one successful connection (for reconnect detection)
  const hasConnectedRef = useRef(false)

  /**
   * Apply a state update eagerly: compute the next value synchronously from
   * cardsRef.current, update the ref, then call setCards with the plain
   * computed value (not a function) so React picks it up on the next render.
   */
  function applyCards(updater) {
    const next = typeof updater === 'function' ? updater(cardsRef.current) : updater
    cardsRef.current = next
    setCards(next)
  }

  function beginOp() { pendingRef.current++; setLoading(true) }
  function endOp()   { if (--pendingRef.current === 0) setLoading(false) }

  function suppressWsEvent(id) {
    suppressedRef.current.set(id, Date.now() + 5000)
  }

  function consumeSuppression(id) {
    const expiry = suppressedRef.current.get(id)
    if (expiry === undefined) return false
    suppressedRef.current.delete(id)
    return Date.now() <= expiry
  }

  // -------------------------------------------------------------------------
  // WebSocket event handler (stub — filled in Subtask 2)
  // -------------------------------------------------------------------------

  // useCallback([]) is safe: applyCards/consumeSuppression close only over stable refs
  const handleWsEvent = useCallback((eventType, payload) => {
    switch (eventType) {
      case 'card:created': {
        if (consumeSuppression(payload.id)) break
        const key = columnToKey(payload.column)
        applyCards(prev => {
          if (prev[key].some(c => c.id === payload.id)) return prev
          return {
            ...prev,
            [key]: [...prev[key], { ...payload, comments: payload.comments ?? [] }]
              .sort((a, b) => a.position - b.position),
          }
        })
        break
      }
      case 'card:updated': {
        if (consumeSuppression(payload.id)) break
        // Remove from current column, re-insert in correct column.
        // Handles both in-place updates AND cross-column moves via PATCH /api/cards/:id.
        // Preserves existing comments (WS payload does not include comments array).
        const newKey = columnToKey(payload.column)
        applyCards(prev => {
          let existingComments = []
          let found = false
          const next = {}
          for (const [k, col] of Object.entries(prev)) {
            const card = col.find(c => c.id === payload.id)
            if (card) { existingComments = card.comments ?? []; found = true }
            next[k] = col.filter(c => c.id !== payload.id)
          }
          if (!found) return prev
          next[newKey] = [...next[newKey], { ...payload, comments: existingComments }]
            .sort((a, b) => a.position - b.position)
          return next
        })
        break
      }
      case 'card:deleted': {
        if (consumeSuppression(payload.id)) break
        applyCards(prev => {
          const next = {}
          for (const [k, col] of Object.entries(prev)) {
            next[k] = col.filter(c => c.id !== payload.id)
          }
          return next
        })
        break
      }
      case 'card:moved': {
        if (consumeSuppression(payload.id)) break
        const newKey = columnToKey(payload.column)
        applyCards(prev => {
          const next = {}
          let existingComments = []
          let found = false
          for (const [k, col] of Object.entries(prev)) {
            const card = col.find(c => c.id === payload.id)
            if (card) { existingComments = card.comments ?? []; found = true }
            next[k] = col.filter(c => c.id !== payload.id)
          }
          if (!found) return prev
          next[newKey] = [...next[newKey], { ...payload, comments: existingComments }]
            .sort((a, b) => a.position - b.position)
          return next
        })
        break
      }
      case 'comment:created': {
        if (consumeSuppression(payload.id)) break
        applyCards(prev => {
          const next = {}
          for (const [k, col] of Object.entries(prev)) {
            next[k] = col.map(c =>
              c.id === payload.card_id
                ? { ...c, comments: [...c.comments, payload] }
                : c
            )
          }
          return next
        })
        break
      }
    }
  }, [])

  const { status: wsStatus } = useWebSocket(WS_URL, { onEvent: handleWsEvent, events: WS_EVENTS })

  // -------------------------------------------------------------------------
  // Reconnect reconciliation — re-fetch on WS reconnect to recover missed events
  // -------------------------------------------------------------------------

  useEffect(() => {
    if (wsStatus === 'connected') {
      if (hasConnectedRef.current) {
        // Reconnect detected — re-fetch to reconcile any missed events
        let cancelled = false
        fetchCards()
          .then(data => { if (!cancelled) applyCards(groupCards(data)) })
          .catch(() => {}) // silent fail; don't disrupt existing state
        return () => { cancelled = true }
      }
      hasConnectedRef.current = true
    }
  }, [wsStatus])

  // -------------------------------------------------------------------------
  // Initial data load
  // -------------------------------------------------------------------------

  useEffect(() => {
    let cancelled = false
    setError(null)
    beginOp()

    fetchCards()
      .then(data => {
        if (cancelled) return
        applyCards(groupCards(data))
        endOp()
      })
      .catch(err => {
        if (cancelled) return
        setError(err.message)
        endOp()
      })

    return () => { cancelled = true }
  }, [])

  // -------------------------------------------------------------------------
  // createCard — temp-ID optimistic pattern
  // -------------------------------------------------------------------------

  const createCard = useCallback(async (data) => {
    const tempId = nextTempId()
    const col = data.column ?? 'ready'
    const key = columnToKey(col)

    const optimisticCard = {
      id: tempId,
      title: data.title,
      assignee: data.assignee ?? null,
      column: col,
      position: Infinity,
      description: data.description ?? null,
      created_at: Date.now(),
      comments: [],
    }

    applyCards(prev => ({ ...prev, [key]: [...prev[key], optimisticCard] }))
    beginOp()

    try {
      const created = await apiCreateCard(data)
      suppressWsEvent(created.id)
      const createdKey = columnToKey(created.column)
      applyCards(prev => {
        const next = { ...prev }
        // Remove the temp card from whichever column it was placed in
        next[key] = next[key].filter(c => c.id !== tempId)
        // Insert the server card into the column the server assigned
        next[createdKey] = [...next[createdKey], created]
          .sort((a, b) => a.position - b.position)
        return next
      })
      return created
    } catch (err) {
      applyCards(prev => ({
        ...prev,
        [key]: prev[key].filter(c => c.id !== tempId),
      }))
      throw err
    } finally {
      endOp()
    }
  }, [])

  // -------------------------------------------------------------------------
  // updateCard — rollback pattern (column changes ignored; use moveCard)
  // -------------------------------------------------------------------------

  const updateCard = useCallback(async (id, data) => {
    // Strip column — column changes must go through moveCard
    const safeData = { ...data }
    delete safeData.column

    // Capture rollback synchronously from the ref (not inside a lazy updater)
    const rollback = cardsRef.current
    suppressWsEvent(id)
    applyCards(prev => {
      const next = {}
      for (const [k, col] of Object.entries(prev)) {
        next[k] = col.map(c => c.id === id ? { ...c, ...safeData } : c)
      }
      return next
    })
    beginOp()

    try {
      const updated = await apiUpdateCard(id, safeData)
      applyCards(prev => {
        const next = {}
        for (const [k, col] of Object.entries(prev)) {
          next[k] = col.map(c => c.id === id ? updated : c)
        }
        return next
      })
      return updated
    } catch (err) {
      applyCards(rollback)
      throw err
    } finally {
      endOp()
    }
  }, [])

  // -------------------------------------------------------------------------
  // deleteCard — rollback pattern
  // -------------------------------------------------------------------------

  const deleteCard = useCallback(async (id) => {
    // Capture rollback synchronously from the ref
    const rollback = cardsRef.current
    suppressWsEvent(id)
    applyCards(prev => {
      const next = {}
      for (const [k, col] of Object.entries(prev)) {
        next[k] = col.filter(c => c.id !== id)
      }
      return next
    })
    beginOp()

    try {
      await apiDeleteCard(id)
    } catch (err) {
      applyCards(rollback)
      throw err
    } finally {
      endOp()
    }
  }, [])

  // -------------------------------------------------------------------------
  // moveCard — rollback pattern
  // targetColumn must be in API format ('ready' | 'in-progress' | 'done')
  // -------------------------------------------------------------------------

  const moveCard = useCallback(async (id, targetColumn, position) => {
    const targetKey = columnToKey(targetColumn)

    // Capture rollback synchronously from the ref
    const rollback = cardsRef.current
    suppressWsEvent(id)
    applyCards(prev => {
      let cardToMove = null
      const next = {}

      for (const [k, col] of Object.entries(prev)) {
        const idx = col.findIndex(c => c.id === id)
        if (idx !== -1) {
          cardToMove = col[idx]
          next[k] = col.filter(c => c.id !== id)
        } else {
          next[k] = col
        }
      }

      if (!cardToMove) return prev

      const movedCard = {
        ...cardToMove,
        column: targetColumn,
        ...(position !== undefined ? { position } : {}),
      }
      next[targetKey] = [...next[targetKey], movedCard]
        .sort((a, b) => a.position - b.position)
      return next
    })
    beginOp()

    try {
      const payload = { column: targetColumn }
      if (position !== undefined) payload.position = position
      const updated = await apiUpdateCard(id, payload)
      const updatedKey = columnToKey(updated.column)
      applyCards(prev => {
        const next = {}
        for (const [k, col] of Object.entries(prev)) {
          next[k] = col.filter(c => c.id !== id)
        }
        next[updatedKey] = [...next[updatedKey], updated]
          .sort((a, b) => a.position - b.position)
        return next
      })
      return updated
    } catch (err) {
      applyCards(rollback)
      throw err
    } finally {
      endOp()
    }
  }, [])

  // -------------------------------------------------------------------------
  // addComment — temp-ID optimistic pattern
  // -------------------------------------------------------------------------

  const addComment = useCallback(async (cardId, data) => {
    const tempId = nextTempId()
    const optimisticComment = {
      id: tempId,
      card_id: cardId,
      author: data.author,
      content: data.content,
      created_at: Date.now(),
    }

    applyCards(prev => {
      const next = {}
      for (const [k, col] of Object.entries(prev)) {
        next[k] = col.map(c =>
          c.id === cardId
            ? { ...c, comments: [...c.comments, optimisticComment] }
            : c
        )
      }
      return next
    })
    beginOp()

    try {
      const comment = await createComment(cardId, data)
      suppressWsEvent(comment.id)
      applyCards(prev => {
        const next = {}
        for (const [k, col] of Object.entries(prev)) {
          next[k] = col.map(c =>
            c.id === cardId
              ? {
                  ...c,
                  comments: c.comments
                    .filter(cm => cm.id !== tempId)
                    .concat(comment),
                }
              : c
          )
        }
        return next
      })
      return comment
    } catch (err) {
      applyCards(prev => {
        const next = {}
        for (const [k, col] of Object.entries(prev)) {
          next[k] = col.map(c =>
            c.id === cardId
              ? { ...c, comments: c.comments.filter(cm => cm.id !== tempId) }
              : c
          )
        }
        return next
      })
      throw err
    } finally {
      endOp()
    }
  }, [])

  // -------------------------------------------------------------------------
  // Public interface
  // -------------------------------------------------------------------------

  return {
    cards,
    loading,
    error,
    createCard,
    updateCard,
    deleteCard,
    moveCard,
    addComment,
  }
}

import { render, screen, fireEvent } from '@testing-library/react'
import { describe, it, expect, vi } from 'vitest'
import CardTile from './CardTile.jsx'

const card = {
  id: '1',
  title: 'Fix bug',
  assignee: 'Alice',
  description: 'Short desc',
  column: 'ready',
  position: 1,
  created_at: Date.now(),
  comments: [],
}

describe('CardTile', () => {
  it('renders card title', () => {
    render(<CardTile card={card} onCardClick={vi.fn()} />)
    expect(screen.getByText('Fix bug')).toBeInTheDocument()
  })

  it('renders assignee name when provided', () => {
    render(<CardTile card={card} onCardClick={vi.fn()} />)
    expect(screen.getByText('Alice')).toBeInTheDocument()
  })

  it("renders 'Unassigned' when assignee is null", () => {
    render(<CardTile card={{ ...card, assignee: null }} onCardClick={vi.fn()} />)
    expect(screen.getByText('Unassigned')).toBeInTheDocument()
  })

  it('renders description when provided', () => {
    render(<CardTile card={card} onCardClick={vi.fn()} />)
    expect(screen.getByText('Short desc')).toBeInTheDocument()
  })

  it('does not render description element when description is null', () => {
    render(<CardTile card={{ ...card, description: null }} onCardClick={vi.fn()} />)
    expect(screen.queryByText('Short desc')).toBeNull()
  })

  it('calls onCardClick with the card object when clicked', () => {
    const handler = vi.fn()
    render(<CardTile card={card} onCardClick={handler} />)
    fireEvent.click(screen.getByRole('button', { name: 'Fix bug' }))
    expect(handler).toHaveBeenCalledWith(card)
  })

  it('calls onCardClick when Enter key is pressed', () => {
    const handler = vi.fn()
    render(<CardTile card={card} onCardClick={handler} />)
    fireEvent.keyDown(screen.getByRole('button'), { key: 'Enter' })
    expect(handler).toHaveBeenCalledWith(card)
  })

  it('calls onCardClick when Space key is pressed', () => {
    const handler = vi.fn()
    render(<CardTile card={card} onCardClick={handler} />)
    fireEvent.keyDown(screen.getByRole('button'), { key: ' ' })
    expect(handler).toHaveBeenCalledWith(card)
  })

  it('is keyboard-focusable', () => {
    render(<CardTile card={card} onCardClick={vi.fn()} />)
    expect(screen.getByRole('button')).toHaveAttribute('tabindex', '0')
  })
})

